  1	import * as React from 'react';
  2	import { DISCOVERED_APP_NS, DRApplication } from '@odf/mco/constants';
  3	import { getDRPlacementControlResourceObj } from '@odf/mco/hooks';
  4	import { DRPlacementControlKind } from '@odf/mco/types';
  5	import {
  6	  getName,
  7	  StatusBox,
  8	  useCustomTranslation,
  9	  DRPlacementControlModel,
 10	} from '@odf/shared';
 11	import NameInputWithValidation from '@odf/shared/input-with-requirements/NameInputWithValidation';
 12	import { ResourceIcon } from '@odf/shared/resource-link/resource-link';
 13	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 14	import { TFunction, Trans } from 'react-i18next';
 15	import {
 16	  Alert,
 17	  AlertVariant,
 18	  Drawer,
 19	  DrawerActions,
 20	  DrawerCloseButton,
 21	  DrawerContent,
 22	  DrawerContentBody,
 23	  DrawerHead,
 24	  DrawerPanelBody,
 25	  DrawerPanelContent,
 26	  Flex,
 27	  Form,
 28	  FormGroup,
 29	  FormHelperText,
 30	  HelperText,
 31	  HelperTextItem,
 32	  Radio,
 33	  Title,
 34	} from '@patternfly/react-core';
 35	import {
 36	  ManagePolicyStateAction,
 37	  ManagePolicyStateType,
 38	  ModalViewContext,
 39	} from '../utils/reducer';
 40	import {
 41	  DRPlacementControlType,
 42	  DRPolicyType,
 43	  VMProtectionType,
 44	} from '../utils/types';
 45	import {
 46	  SharedVMGroupsTable,
 47	  ViewSharedVMGroupTable,
 48	} from './shared-virtual-machine-table';
 49	
 50	const RADIO_GROUP_NAME = 'vm_protection_method';
 51	
 52	const ProtectionNameInput: React.FC<ProtectionNameInputProps> = ({
 53	  vmProtectionName,
 54	  dispatch,
 55	}) => {
 56	  const { t } = useCustomTranslation();
 57	  const [drpcs, drpcsLoaded, drpcsLoadError] = useK8sWatchResource<
 58	    DRPlacementControlKind[]
 59	  >(
 60	    getDRPlacementControlResourceObj({
 61	      namespace: DISCOVERED_APP_NS,
 62	    })
 63	  );
 64	
 65	  const existingProtectionNames = React.useMemo(() => {
 66	    // Ensure drpcs is loaded and valid before processing
 67	    if (!drpcsLoaded || drpcsLoadError) return [];
 68	
 69	    return drpcs.map(getName);
 70	  }, [drpcs, drpcsLoaded, drpcsLoadError]);
 71	
 72	  const setProtectionName = (newName: string) => {
 73	    dispatch({
 74	      type: ManagePolicyStateType.SET_VM_PROTECTION_NAME,
 75	      context: ModalViewContext.ASSIGN_POLICY_VIEW,
 76	      payload: newName,
 77	    });
 78	  };
 79	
 80	  return drpcsLoaded && !drpcsLoadError ? (
 81	    <NameInputWithValidation
 82	      label={t('Protection name')}
 83	      helperText={t('A unique name to identify and manage this protection.')}
 84	      name={vmProtectionName}
 85	      existingNames={existingProtectionNames}
 86	      onChange={setProtectionName}
 87	    />
 88	  ) : (
 89	    <StatusBox loaded={drpcsLoaded} loadError={drpcsLoadError} />
 90	  );
 91	};
 92	
 93	const getRadioOptions = (
 94	  isDiscoveredApp: boolean,
 95	  protectionName: string,
 96	  dispatch: React.Dispatch<ManagePolicyStateAction>,
 97	  t: TFunction,
 98	  matchingPolicies: DRPolicyType[],
 99	  sharedVMGroups: DRPlacementControlType[],
100	  sharedVMGroup: DRPlacementControlType,
101	  toggleDrawer: (sharedVMGroup: DRPlacementControlType) => void
102	): RadioOption[] => {
103	  const options: RadioOption[] = [
104	    {
105	      id: 'standalone-vm-protection',
106	      value: VMProtectionType.STANDALONE,
107	      description: t(
108	        'Protect this VM independently without associating it with an existing DR placement control.'
109	      ),
110	      label: t('Standalone'),
111	      isDisabled: false,
112	      ...(isDiscoveredApp && {
113	        componentRef: (
114	          <ProtectionNameInput
115	            vmProtectionName={protectionName}
116	            dispatch={dispatch}
117	          />
118	        ),
119	      }),
120	    },
121	    {
122	      id: 'shared-vm-protection',
123	      value: VMProtectionType.SHARED,
124	      description: t(
125	        'Add this VM to an existing DR placement control for consistent failover and recovery. This method is only available for discovered VMs.'
126	      ),
127	      label: t('Shared'),
128	      isDisabled: !isDiscoveredApp || !sharedVMGroups.length,
129	      ...(isDiscoveredApp && {
130	        componentRef: (
131	          <SharedVMGroupsTable
132	            sharedVMGroup={sharedVMGroup}
133	            sharedVMGroups={sharedVMGroups}
134	            matchingPolicies={matchingPolicies}
135	            toggleDrawer={toggleDrawer}
136	            dispatch={dispatch}
137	          />
138	        ),
139	      }),
140	    },
141	  ];
142	
143	  return options;
144	};
145	
146	const ProtectionTypeSelection: React.FC<ProtectionTypeSelectionProps> = ({
147	  protectionType,
148	  protectionName,
149	  appType,
150	  dispatch,
151	  matchingPolicies,
152	  sharedVMGroups,
153	  sharedVMGroup,
154	  toggleDrawer,
155	}) => {
156	  const { t } = useCustomTranslation();
157	
158	  const isDiscoveredApp = appType === DRApplication.DISCOVERED;
159	
160	  const setProtectionMethod = (event: React.ChangeEvent<HTMLInputElement>) =>
161	    dispatch({
162	      type: ManagePolicyStateType.SET_VM_PROTECTION_METHOD,
163	      context: ModalViewContext.ASSIGN_POLICY_VIEW,
164	      payload: event.target.value as VMProtectionType,
165	    });
166	
167	  const radioOptions = React.useMemo(
168	    () =>
169	      getRadioOptions(
170	        isDiscoveredApp,
171	        protectionName,
172	        dispatch,
173	        t,
174	        matchingPolicies,
175	        sharedVMGroups,
176	        sharedVMGroup,
177	        toggleDrawer
178	      ),
179	    [
180	      isDiscoveredApp,
181	      protectionName,
182	      dispatch,
183	      t,
184	      matchingPolicies,
185	      sharedVMGroups,
186	      sharedVMGroup,
187	      toggleDrawer,
188	    ]
189	  );
190	
191	  return (
192	    <Form>
193	      <FormGroup label={t('Protection type')} fieldId="vm-protection-method">
194	        <FormHelperText className="pf-v6-u-mb-sm">
195	          <HelperText>
196	            <HelperTextItem variant="indeterminate">
197	              {t('Choose how you would like to protect this VM:')}
198	            </HelperTextItem>
199	          </HelperText>
200	        </FormHelperText>
201	
202	        {radioOptions.map(
203	          ({ id, value, description, label, isDisabled, componentRef }) => (
204	            <Radio
205	              key={id}
206	              id={id}
207	              name={RADIO_GROUP_NAME}
208	              value={value}
209	              description={description}
210	              label={label}
211	              onChange={setProtectionMethod}
212	              isChecked={protectionType === value}
213	              isDisabled={isDisabled}
214	              className="pf-v6-u-mb-md"
215	              body={protectionType === value && componentRef}
216	            />
217	          )
218	        )}
219	
220	        {!isDiscoveredApp && (
221	          <Alert
222	            title={t('Shared protection is not available for managed VMs.')}
223	            variant={AlertVariant.info}
224	            isInline
225	          />
226	        )}
227	      </FormGroup>
228	    </Form>
229	  );
230	};
231	
232	export const ProtectionTypeWizardContent: React.FC<
233	  ProtectionTypeWizardContentProps
234	> = ({
235	  protectionType,
236	  protectionName,
237	  appType,
238	  dispatch,
239	  matchingPolicies,
240	  sharedVMGroups,
241	}) => {
242	  const { t } = useCustomTranslation();
243	  const drawerRef = React.useRef<HTMLDivElement>(null);
244	  const [isExpanded, setIsExpanded] = React.useState(false);
245	  const [viewSharedVMGroup, setViewSharedGroup] =
246	    React.useState<DRPlacementControlType>();
247	
248	  const toggleDrawer = React.useCallback(
249	    (sharedVMGroup?: DRPlacementControlType) => {
250	      setViewSharedGroup(sharedVMGroup);
251	      setIsExpanded((prev) => !prev);
252	    },
253	    []
254	  );
255	
256	  const onExpand = () => drawerRef.current?.focus();
257	
258	  const sharedVMGroup = sharedVMGroups?.find(
259	    (group) => group.vmSharedGroupName === protectionName
260	  );
261	
262	  const sharedGroupName = getName(viewSharedVMGroup);
263	
264	  return (
265	    <Drawer isExpanded={isExpanded} onExpand={onExpand}>
266	      <DrawerContent
267	        panelContent={
268	          <DrawerPanelContent>
269	            <Flex>
270	              <DrawerHead>
271	                <Title
272	                  headingLevel="h4"
273	                  tabIndex={isExpanded ? 0 : -1}
274	                  ref={drawerRef}
275	                >
276	                  {t('Virtual machines ({{count}})', {
277	                    count: viewSharedVMGroup?.vmSharedGroup?.length,
278	                  })}
279	                </Title>
280	                <DrawerActions>
281	                  <DrawerCloseButton onClick={() => toggleDrawer()} />
282	                </DrawerActions>
283	                <Trans t={t}>
284	                  <span>
285	                    Showing all VMs grouped under{' '}
286	                    <ResourceIcon resourceModel={DRPlacementControlModel} />
287	                    {{ sharedGroupName }}
288	                  </span>
289	                </Trans>
290	              </DrawerHead>
291	            </Flex>
292	            <DrawerPanelBody>
293	              {viewSharedVMGroup && (
294	                <ViewSharedVMGroupTable sharedVMGroup={viewSharedVMGroup} />
295	              )}
296	            </DrawerPanelBody>
297	          </DrawerPanelContent>
298	        }
299	      >
300	        <DrawerContentBody>
301	          <ProtectionTypeSelection
302	            {...{
303	              protectionType,
304	              protectionName,
305	              appType,
306	              matchingPolicies,
307	              sharedVMGroups,
308	              sharedVMGroup,
309	              toggleDrawer,
310	              dispatch,
311	            }}
312	          />
313	        </DrawerContentBody>
314	      </DrawerContent>
315	    </Drawer>
316	  );
317	};
318	
319	type ProtectionTypeWizardContentProps = {
320	  protectionType: VMProtectionType;
321	  protectionName: string;
322	  appType: DRApplication;
323	  dispatch: React.Dispatch<ManagePolicyStateAction>;
324	  matchingPolicies: DRPolicyType[];
325	  sharedVMGroups: DRPlacementControlType[];
326	};
327	
328	type ProtectionTypeSelectionProps = ProtectionTypeWizardContentProps & {
329	  sharedVMGroup: DRPlacementControlType;
330	  toggleDrawer: (sharedVMGroup: DRPlacementControlType) => void;
331	};
332	
333	type RadioOption = {
334	  id: string;
335	  value: VMProtectionType;
336	  description: string;
337	  label: string;
338	  isDisabled: boolean;
339	  componentRef?: React.ReactNode;
340	};
341	
342	type ProtectionNameInputProps = {
343	  vmProtectionName: string;
344	  dispatch: React.Dispatch<ManagePolicyStateAction>;
345	};
346	
347	export default ProtectionTypeWizardContent;

